import{_ as t,c as i,o as n,a1 as r}from"./chunks/framework.DILC4Csi.js";const p=JSON.parse('{"title":"Authentifizierungsfehler: 401 Fehlerbehebung | Antigravity-Manager","description":"Lernen Sie den Authentifizierungsmechanismus des Antigravity-Tools-Proxys, beheben Sie 401-Fehler. Lokalisieren Sie Probleme in der Reihenfolge auth_mode, api_key, Header, verstehen Sie die Auto-Modus-Regeln und /healthz-Ausnahme, vermeiden Sie Fehlurteile zur Header-Priorität.","frontmatter":{"title":"Authentifizierungsfehler: 401 Fehlerbehebung | Antigravity-Manager","sidebarTitle":"401 in 3 Minuten lösen","subtitle":"401/Authentifizierungsfehler: Zuerst auth_mode prüfen, dann Header","description":"Lernen Sie den Authentifizierungsmechanismus des Antigravity-Tools-Proxys, beheben Sie 401-Fehler. Lokalisieren Sie Probleme in der Reihenfolge auth_mode, api_key, Header, verstehen Sie die Auto-Modus-Regeln und /healthz-Ausnahme, vermeiden Sie Fehlurteile zur Header-Priorität.","tags":["FAQ","Authentifizierung","401","API Key"],"prerequisite":["start-proxy-and-first-client"],"order":2},"headers":[],"relativePath":"de/lbjlaq/Antigravity-Manager/faq/auth-401/index.md","filePath":"de/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"}'),a={name:"de/lbjlaq/Antigravity-Manager/faq/auth-401/index.md"};function d(s,e,o,l,h,c){return n(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="_401-authentifizierungsfehler-zuerst-auth-mode-prufen-dann-header" tabindex="-1">401/Authentifizierungsfehler: Zuerst auth_mode prüfen, dann Header <a class="header-anchor" href="#_401-authentifizierungsfehler-zuerst-auth-mode-prufen-dann-header" aria-label="Permalink to &quot;401/Authentifizierungsfehler: Zuerst auth_mode prüfen, dann Header&quot;">​</a></h1><h2 id="lernziele" tabindex="-1">Lernziele <a class="header-anchor" href="#lernziele" aria-label="Permalink to &quot;Lernziele&quot;">​</a></h2><ul><li>Beurteilen Sie in 3 Minuten, ob 401 durch die Authentifizierungs-Middleware von Antigravity Tools blockiert wurde</li><li>Verstehen Sie die &quot;tatsächlichen effektiven Werte&quot; der vier <code>proxy.auth_mode</code>-Modi (insbesondere <code>auto</code>) in Ihrer aktuellen Konfiguration</li><li>Lassen Sie Anfragen mit dem korrekten API Key Header (und vermeiden Sie die Header-Prioritätsfalle) passieren</li></ul><h2 id="ihr-aktuelles-problem" tabindex="-1">Ihr aktuelles Problem <a class="header-anchor" href="#ihr-aktuelles-problem" aria-label="Permalink to &quot;Ihr aktuelles Problem&quot;">​</a></h2><p>Der Client erhält den Fehler <code>401 Unauthorized</code> beim Aufruf des lokalen Reverse-Proxys:</p><ul><li>Python/OpenAI SDK: Löst <code>AuthenticationError</code> aus</li><li>curl: Gibt <code>HTTP/1.1 401 Unauthorized</code> zurück</li><li>HTTP-Client: Antwortstatuscode 401</li></ul><h2 id="was-ist-401-authentifizierungsfehler" tabindex="-1">Was ist 401/Authentifizierungsfehler? <a class="header-anchor" href="#was-ist-401-authentifizierungsfehler" aria-label="Permalink to &quot;Was ist 401/Authentifizierungsfehler?&quot;">​</a></h2><p><strong>401 Unauthorized</strong> bedeutet in Antigravity Tools am häufigsten: Der Proxy hat die Authentifizierung aktiviert (bestimmt durch <code>proxy.auth_mode</code>), aber die Anfrage hat keinen korrekten API Key oder enthält einen Header mit höherer Priorität, der nicht übereinstimmt, daher gibt <code>auth_middleware()</code> direkt 401 zurück.</p><div class="info custom-block"><p class="custom-block-title">Stellen Sie zuerst fest, ob es der &quot;Proxy blockiert&quot;</p><p>Die Upstream-Plattform kann ebenfalls 401 zurückgeben, aber dieses FAQ behandelt nur &quot;durch Proxy-Authentifizierung verursachte 401&quot;. Sie können zuerst mit dem untenstehenden <code>/healthz</code> schnell unterscheiden.</p></div><h2 id="schnelle-fehlerbehebung-in-dieser-reihenfolge" tabindex="-1">Schnelle Fehlerbehebung (in dieser Reihenfolge) <a class="header-anchor" href="#schnelle-fehlerbehebung-in-dieser-reihenfolge" aria-label="Permalink to &quot;Schnelle Fehlerbehebung (in dieser Reihenfolge)&quot;">​</a></h2><h3 id="schritt-1-bestimmen-sie-mit-healthz-ob-authentifizierung-sie-blockiert" tabindex="-1">Schritt 1: Bestimmen Sie mit <code>/healthz</code>, ob &quot;Authentifizierung Sie blockiert&quot; <a class="header-anchor" href="#schritt-1-bestimmen-sie-mit-healthz-ob-authentifizierung-sie-blockiert" aria-label="Permalink to &quot;Schritt 1: Bestimmen Sie mit `/healthz`, ob &quot;Authentifizierung Sie blockiert&quot;&quot;">​</a></h3><p><strong>Warum</strong><code>all_except_health</code> lässt <code>/healthz</code> passieren, blockiert aber andere Routen; dies hilft Ihnen, schnell zu lokalisieren, ob 401 von der Proxy-Authentifizierungsschicht stammt.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Ohne Authentifizierungs-Header</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/healthz</span></span></code></pre></div><p><strong>Sie sollten sehen</strong></p><ul><li>Wenn <code>auth_mode=all_except_health</code> (oder <code>auto</code> und <code>allow_lan_access=true</code>): Normalerweise wird <code>200</code> zurückgegeben</li><li>Wenn <code>auth_mode=strict</code>: Es wird <code>401</code> zurückgegeben</li></ul><div class="tip custom-block"><p class="custom-block-title"><code>/healthz</code> ist in der Routing-Schicht GET</p><p>Der Proxy registriert <code>GET /healthz</code> in den Routen (siehe <code>src-tauri/src/proxy/server.rs</code>).</p></div><hr><h3 id="schritt-2-bestatigen-sie-den-tatsachlichen-effektiven-wert-von-auth-mode-insbesondere-auto" tabindex="-1">Schritt 2: Bestätigen Sie den &quot;tatsächlichen effektiven Wert&quot; von <code>auth_mode</code> (insbesondere <code>auto</code>) <a class="header-anchor" href="#schritt-2-bestatigen-sie-den-tatsachlichen-effektiven-wert-von-auth-mode-insbesondere-auto" aria-label="Permalink to &quot;Schritt 2: Bestätigen Sie den &quot;tatsächlichen effektiven Wert&quot; von `auth_mode` (insbesondere `auto`)&quot;">​</a></h3><p><strong>Warum</strong><code>auto</code> ist keine &quot;unabhängige Strategie&quot;, sie berechnet den tatsächlich auszuführenden Modus basierend auf <code>allow_lan_access</code>.</p><table tabindex="0"><thead><tr><th><code>proxy.auth_mode</code></th><th>Zusätzliche Bedingung</th><th>Tatsächlicher effektiver Wert</th></tr></thead><tbody><tr><td><code>off</code></td><td>-</td><td><code>off</code></td></tr><tr><td><code>strict</code></td><td>-</td><td><code>strict</code></td></tr><tr><td><code>all_except_health</code></td><td>-</td><td><code>all_except_health</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=false</code></td><td><code>off</code></td></tr><tr><td><code>auto</code></td><td><code>allow_lan_access=true</code></td><td><code>all_except_health</code></td></tr></tbody></table><p><strong>Sie können dies auf der Seite API Proxy in der GUI prüfen</strong>: <code>Allow LAN Access</code> und <code>Auth Mode</code>.</p><hr><h3 id="schritt-3-bestatigen-sie-dass-api-key-nicht-leer-ist-und-sie-denselben-wert-verwenden" tabindex="-1">Schritt 3: Bestätigen Sie, dass <code>api_key</code> nicht leer ist und Sie denselben Wert verwenden <a class="header-anchor" href="#schritt-3-bestatigen-sie-dass-api-key-nicht-leer-ist-und-sie-denselben-wert-verwenden" aria-label="Permalink to &quot;Schritt 3: Bestätigen Sie, dass `api_key` nicht leer ist und Sie denselben Wert verwenden&quot;">​</a></h3><p><strong>Warum</strong> Wenn die Authentifizierung aktiviert ist und <code>proxy.api_key</code> leer ist, lehnt <code>auth_middleware()</code> alle Anfragen ab und protokolliert den Fehler.</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Proxy auth is enabled but api_key is empty; denying request</span></span></code></pre></div><p><strong>Sie sollten sehen</strong></p><ul><li>Auf der Seite API Proxy sehen Sie einen Key, der mit <code>sk-</code> beginnt (der Standardwert wird automatisch in <code>ProxyConfig::default()</code> generiert)</li><li>Nach dem Klicken auf &quot;Regenerate/Bearbeiten&quot; und Speichern werden externe Anfragen sofort mit dem neuen Key überprüft (kein Neustart erforderlich)</li></ul><hr><h3 id="schritt-4-testen-sie-einmal-mit-dem-einfachsten-header-verwenden-sie-zunachst-keine-komplexen-sdks" tabindex="-1">Schritt 4: Testen Sie einmal mit dem einfachsten Header (verwenden Sie zunächst keine komplexen SDKs) <a class="header-anchor" href="#schritt-4-testen-sie-einmal-mit-dem-einfachsten-header-verwenden-sie-zunachst-keine-komplexen-sdks" aria-label="Permalink to &quot;Schritt 4: Testen Sie einmal mit dem einfachsten Header (verwenden Sie zunächst keine komplexen SDKs)&quot;">​</a></h3><p><strong>Warum</strong> Die Middleware liest zuerst <code>Authorization</code>, dann <code>x-api-key</code> und schließlich <code>x-goog-api-key</code>. Wenn Sie mehrere Header gleichzeitig senden, wird der vorherige verwendet, selbst wenn er falsch ist, und der spätere, selbst wenn er korrekt ist, nicht verwendet.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # Empfohlene Schreibweise: Authorization + Bearer</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Authorization: Bearer sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><p><strong>Sie sollten sehen</strong>: <code>HTTP/1.1 200 OK</code> (oder zumindest nicht mehr 401)</p><div class="info custom-block"><p class="custom-block-title">Proxy-Kompatibilitätsdetails für Authorization</p><p><code>auth_middleware()</code> entfernt den Wert von <code>Authorization</code> einmal basierend auf dem Präfix <code>Bearer </code>; wenn kein <code>Bearer </code>-Präfix vorhanden ist, wird der gesamte Wert als Key zum Vergleich verwendet. Die Dokumentation empfiehlt weiterhin <code>Authorization: Bearer &lt;key&gt;</code> (entspricht besser der allgemeinen SDK-Konvention).</p></div><p><strong>Wenn Sie <code>x-api-key</code> verwenden müssen</strong>:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> http://127.0.0.1:8045/v1/models</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>\n<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  -H</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;x-api-key: sk-REPLACE_WITH_YOUR_PROXY_API_KEY&quot;</span></span></code></pre></div><hr><h2 id="haufige-fallen-alles-passiert-im-quellcode" tabindex="-1">Häufige Fallen (alles passiert im Quellcode) <a class="header-anchor" href="#haufige-fallen-alles-passiert-im-quellcode" aria-label="Permalink to &quot;Häufige Fallen (alles passiert im Quellcode)&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Phänomen</th><th>Wahrer Grund</th><th>Wie Sie ändern sollten</th></tr></thead><tbody><tr><td><code>auth_mode=auto</code>, aber lokaler Aufruf immer noch 401</td><td><code>allow_lan_access=true</code> führt dazu, dass <code>auto</code> zu <code>all_except_health</code> wird</td><td>Deaktivieren Sie <code>allow_lan_access</code> oder lassen Sie den Client den Key mitbringen</td></tr><tr><td>Sie denken &quot;ich habe x-api-key mitgebracht&quot;, aber immer noch 401</td><td>Gleichzeitig einen nicht übereinstimmenden <code>Authorization</code> mitgebracht, Middleware verwendet ihn priorisiert</td><td>Löschen Sie überflüssige Header, behalten Sie nur einen, von dem Sie sicher sind, dass er korrekt ist</td></tr><tr><td><code>Authorization: Bearer&lt;key&gt;</code> immer noch 401</td><td>Fehlendes Leerzeichen nach <code>Bearer</code>, kann nicht nach dem Präfix <code>Bearer </code> entfernt werden</td><td>Ändern Sie in <code>Authorization: Bearer &lt;key&gt;</code></td></tr><tr><td>Alle Anfragen sind 401, Protokoll zeigt <code>api_key is empty</code></td><td><code>proxy.api_key</code> ist leer</td><td>Generieren/legen Sie einen nicht-leeren Key in der GUI fest</td></tr></tbody></table><h2 id="zusammenfassung-dieser-lektion" tabindex="-1">Zusammenfassung dieser Lektion <a class="header-anchor" href="#zusammenfassung-dieser-lektion" aria-label="Permalink to &quot;Zusammenfassung dieser Lektion&quot;">​</a></h2><ul><li>Verwenden Sie zuerst <code>/healthz</code>, um zu lokalisieren, ob 401 von der Proxy-Authentifizierungsschicht stammt</li><li>Bestätigen Sie dann <code>auth_mode</code> (insbesondere den effektiven Modus von <code>auto</code>)</li><li>Senden Sie schließlich nur einen Header, von dem Sie sicher sind, dass er korrekt ist, zur Überprüfung (vermeiden Sie die Header-Prioritätsfalle)</li></ul><h2 id="vorschau-auf-die-nachste-lektion" tabindex="-1">Vorschau auf die nächste Lektion <a class="header-anchor" href="#vorschau-auf-die-nachste-lektion" aria-label="Permalink to &quot;Vorschau auf die nächste Lektion&quot;">​</a></h2><blockquote><p>In der nächsten Lektion lernen wir <strong><a href="./../429-rotation/">429/Kapazitätsfehler: Richtige Erwartungen an Kontorotation und Missverständnisse über erschöpfte Modellkapazität</a></strong>.</p><p>Sie werden lernen:</p><ul><li>Ob 429 &quot;Kontingentmangel&quot; oder &quot;Upstream-Ratenbegrenzung&quot; ist</li><li>Richtige Erwartungen an Kontorotation (wann automatisch gewechselt wird und wann nicht)</li><li>Konfigurieren, um die Wahrscheinlichkeit von 429 zu verringern</li></ul></blockquote><hr><h2 id="anhang-quellcode-referenz" tabindex="-1">Anhang: Quellcode-Referenz <a class="header-anchor" href="#anhang-quellcode-referenz" aria-label="Permalink to &quot;Anhang: Quellcode-Referenz&quot;">​</a></h2><details><summary><strong>Klicken, um Quellcodepositionen anzuzeigen</strong></summary><blockquote><p>Aktualisierungszeit: 2026-01-23</p></blockquote><table tabindex="0"><thead><tr><th>Funktion</th><th>Dateipfad</th><th>Zeilennummer</th></tr></thead><tbody><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>ProxyConfig: allow_lan_access/auth_mode/api_key und Standardwerte</td><td><a href="https://github.com/lbjlaq/Antigravity-Manager/blob/main/src-tauri/src/proxy/config.rs#L174-L258" target="_blank" rel="noreferrer"><code>src-tauri/src/proxy/config.rs</code></a></td><td>174-258</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr><tr><td>---</td><td>---</td><td>---</td></tr></tbody></table><p><strong>Wichtige Enumerationen</strong>:</p><ul><li><code>ProxyAuthMode::{Off, Strict, AllExceptHealth, Auto}</code>: Authentifizierungsmodi</li></ul><p><strong>Wichtige Funktionen</strong>:</p><ul><li><code>ProxySecurityConfig::effective_auth_mode()</code>: Wandelt <code>auto</code> in eine echte Strategie um</li><li><code>auth_middleware()</code>: Führt Authentifizierung durch (inklusive Header-Extraktionsreihenfolge und /healthz-Ausnahme)</li></ul></details>',45)])])}const g=t(a,[["render",d]]);export{p as __pageData,g as default};
